package org.apache.commons.csv;
import java.io.BufferedReader;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class ExtendedBufferedReaderTest {

    private ExtendedBufferedReader extendedBufferedReader;
    private Reader mockReader;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
        extendedBufferedReader = new ExtendedBufferedReader(mockReader) {
            // Override read(char[], int, int) to call super.read(char[], int, int)
            @Override
            public int read(char[] buf, int offset, int length) throws IOException {
                return super.read(buf, offset, length);
            }
        };
    }

    @Test
    void testReadLengthZeroReturnsZero() throws IOException {
        char[] buffer = new char[10];
        int result = extendedBufferedReader.read(buffer, 0, 0);
        assertEquals(0, result);
    }

    @Test
    void testReadReturnsMinusOneSetsLastCharToEndOfStream() throws IOException {
        char[] buffer = new char[10];
        // Spy on extendedBufferedReader to mock super.read call
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doReturn(-1).when(spyReader).read(any(char[].class), anyInt(), anyInt());

        int result = spyReader.read(buffer, 0, 5);
        assertEquals(-1, result);

        // Use reflection to check lastChar field is END_OF_STREAM
        int lastChar = getPrivateIntField(spyReader, "lastChar");
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, lastChar);
    }

    @Test
    void testReadWithNoNewlineOrCarriageReturnInBuffer() throws IOException {
        char[] buffer = new char[5];
        buffer[0] = 'a';
        buffer[1] = 'b';
        buffer[2] = 'c';
        buffer[3] = 'd';
        buffer[4] = 'e';

        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doAnswer(invocation -> {
            char[] buf = invocation.getArgument(0);
            System.arraycopy(buffer, 0, buf, 0, 5);
            return 5;
        }).when(spyReader).read(any(char[].class), anyInt(), anyInt());

        int result = spyReader.read(new char[5], 0, 5);
        assertEquals(5, result);

        int lineCounter = getPrivateIntField(spyReader, "lineCounter");
        assertEquals(0, lineCounter);

        int lastChar = getPrivateIntField(spyReader, "lastChar");
        assertEquals('e', lastChar);
    }

    @Test
    void testReadWithNewlineNotPrecededByCarriageReturnInBuffer() throws IOException {
        char[] buffer = new char[]{'a', '\n', 'b', 'c', 'd'};

        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doAnswer(invocation -> {
            char[] buf = invocation.getArgument(0);
            System.arraycopy(buffer, 0, buf, 0, buffer.length);
            return buffer.length;
        }).when(spyReader).read(any(char[].class), anyInt(), anyInt());

        int result = spyReader.read(new char[5], 0, 5);
        assertEquals(5, result);

        int lineCounter = getPrivateIntField(spyReader, "lineCounter");
        // '\n' at index 1, previous char 'a' != '\r', so lineCounter increments by 1
        assertEquals(1, lineCounter);

        int lastChar = getPrivateIntField(spyReader, "lastChar");
        assertEquals('d', lastChar);
    }

    @Test
    void testReadWithNewlinePrecededByCarriageReturnInBuffer() throws IOException {
        char[] buffer = new char[]{'a', '\r', '\n', 'b', 'c'};

        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doAnswer(invocation -> {
            char[] buf = invocation.getArgument(0);
            System.arraycopy(buffer, 0, buf, 0, buffer.length);
            return buffer.length;
        }).when(spyReader).read(any(char[].class), anyInt(), anyInt());

        int result = spyReader.read(new char[5], 0, 5);
        assertEquals(5, result);

        int lineCounter = getPrivateIntField(spyReader, "lineCounter");
        // '\r' at index 1 increments lineCounter by 1
        // '\n' at index 2 preceded by '\r' so no increment for '\n'
        assertEquals(1, lineCounter);

        int lastChar = getPrivateIntField(spyReader, "lastChar");
        assertEquals('c', lastChar);
    }

    @Test
    void testReadWithNewlineAtZeroIndexAndLastCharNotCarriageReturn() throws IOException, Exception {
        char[] buffer = new char[]{'\n', 'a', 'b', 'c', 'd'};

        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doAnswer(invocation -> {
            char[] buf = invocation.getArgument(0);
            System.arraycopy(buffer, 0, buf, 0, buffer.length);
            return buffer.length;
        }).when(spyReader).read(any(char[].class), anyInt(), anyInt());

        // Set lastChar to a value not '\r' (e.g. 'x')
        setPrivateIntField(spyReader, "lastChar", 'x');

        int result = spyReader.read(new char[5], 0, 5);
        assertEquals(5, result);

        int lineCounter = getPrivateIntField(spyReader, "lineCounter");
        // '\n' at index 0, previous char is lastChar 'x' != '\r', so lineCounter increments by 1
        assertEquals(1, lineCounter);

        int lastChar = getPrivateIntField(spyReader, "lastChar");
        assertEquals('d', lastChar);
    }

    @Test
    void testReadWithNewlineAtZeroIndexAndLastCharIsCarriageReturn() throws IOException, Exception {
        char[] buffer = new char[]{'\n', 'a', 'b', 'c', 'd'};

        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doAnswer(invocation -> {
            char[] buf = invocation.getArgument(0);
            System.arraycopy(buffer, 0, buf, 0, buffer.length);
            return buffer.length;
        }).when(spyReader).read(any(char[].class), anyInt(), anyInt());

        // Set lastChar to '\r'
        setPrivateIntField(spyReader, "lastChar", '\r');

        int result = spyReader.read(new char[5], 0, 5);
        assertEquals(5, result);

        int lineCounter = getPrivateIntField(spyReader, "lineCounter");
        // '\n' at index 0, previous char is lastChar '\r', so no increment
        assertEquals(0, lineCounter);

        int lastChar = getPrivateIntField(spyReader, "lastChar");
        assertEquals('d', lastChar);
    }

    private int getPrivateIntField(Object instance, String fieldName) {
        try {
            Field field = ExtendedBufferedReader.class.getDeclaredField(fieldName);
            field.setAccessible(true);
            return field.getInt(instance);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    private void setPrivateIntField(Object instance, String fieldName, int value) {
        try {
            Field field = ExtendedBufferedReader.class.getDeclaredField(fieldName);
            field.setAccessible(true);
            field.setInt(instance, value);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
